
print ("Esse programa calcula o delta de uma eq 2o grau...")
a = float (input("Digite o valor de a:"))
b = float (input("Digite o valor de b:"))
c = float (input("Digite o valor de c:"))

#Calculando o Delta (b**2 - 4ac)
delta= (b**2) - (4*a*c)

print(f"Para a equação {a}x**2+{b} x {c} = 0")
print("O valor de delta é:", delta, "Parabéns, agora você sabe o valor de delta")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      